definition.script:
import groovy.json.JsonSlurper;

def infrastructure_git_hash

pipeline {
  agent any

  options {
    skipDefaultCheckout(true)
  }

  stages {
    stage('Resolve Infrastructure Git Hash') {
      steps {
        script {
          if (params.INFRASTRUCTURE_GIT_HASH?.trim()) {
            infrastructure_git_hash = params.INFRASTRUCTURE_GIT_HASH.trim()
            echo "Using provided INFRASTRUCTURE_GIT_HASH: ${infrastructure_git_hash}"
          } else {
            def result = build job: 'Retrieve Build Spec'
            copyArtifacts filter: 'build-spec.json', projectName: 'Retrieve Build Spec', selector: specific("" + result.number)
            def buildSpec = new JsonSlurper().parse(new File("${env.WORKSPACE}/build-spec.json"))
            infrastructure_git_hash = buildSpec.infrastructure_git_hash
            echo "Resolved INFRASTRUCTURE_GIT_HASH from release control: ${infrastructure_git_hash}"
          }
        }
      }
    }

    stage('Checkout Infrastructure Repo') {
      steps {
        checkout([
          $class: 'GitSCM',
          userRemoteConfigs: [[
            url: "${infrastructure_git_repo}",
            credentialsId: "${git_credentials_id}"
          ]],
          branches: [[name: infrastructure_git_hash]]
        ])
      }
    }

    stage('Download Template') {
      steps {
        script {
          def repoTemplate = 'app-infrastructure/template-renderer/templates/visualization.env.tftpl'
          def targetStack = params.TARGET_STACK?.trim() ?: ''

          sh '''#!/bin/bash
            source_scripts_folder="${JENKINS_HOME}/workspace/Bash_Functions/"
            for script_file in "$source_scripts_folder"*.sh; do
                chmod +x "$script_file"
                if [ -f "$script_file" ] && [ -x "$script_file" ]; then
                    source "$script_file"
                fi
            done
          '''

          def found = false
          if (targetStack) {
            found = sh(script: "aws s3 cp s3://\${stack_s3_bucket}/configs/pic-sure-visualization/templates/${targetStack}/visualization.env.tftpl visualization.env.tftpl", returnStatus: true) == 0
            if (found) echo "Using stack-specific S3 template for visualization.env.tftpl"
          }
          if (!found) {
            found = sh(script: "aws s3 cp s3://\${stack_s3_bucket}/configs/pic-sure-visualization/templates/visualization.env.tftpl visualization.env.tftpl", returnStatus: true) == 0
            if (found) echo "Using shared S3 template for visualization.env.tftpl"
          }
          if (!found) {
            echo "No S3 template found, using repo version of visualization.env.tftpl"
            sh "cp ${repoTemplate} visualization.env.tftpl"
          }
        }
      }
    }
  }

  post {
    success {
      archiveArtifacts artifacts: 'visualization.env.tftpl', allowEmptyArchive: true
    }
  }
}
